private IneqTree Balls(double r)
{
  	var balls = new IneqTree();

  	var pol = Ineq3DOnline.PlatonicSolids.Polyhedron.CreateGeodesicSphere(1.0);
  
  	foreach (var v in pol.Vertices)
    {
		balls = balls | Ball(1.2 * v.X, 1.2 * v.Y, 1.2 * v.Z, r);      
    } 
  
   	return balls;
}

public IneqMesh GetIneqMesh()
{
    var res = new IneqMesh
    {
        X0 = -1.2,
        Y0 = -1.2,
        Z0 = -1.2,
        X1 = 1.2,
        Y1 = 1.2,
        Z1 = 1.2,
        D = 0.06,
        Boxed = true,
        IneqTree = Ball(0,0,0,1.0) & !Balls(0.3)
	};

  
  	return res;
}
